#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->filter_on = false;
    controller->drain_open = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_turbidity = false;
    controller->last_turbidity_ntu = 0;
    controller->last_turbidity_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
    controller->clear_streak_count = 0;
    controller->settling_started_ms = 0U;
}

static bool is_sensor_stale(uint32_t last_seen_ms, uint32_t now_ms)
{
    return (now_ms - last_seen_ms) > CONTROLLER_SENSOR_TIMEOUT_MS;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .filter_on = false,
        .drain_open = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };

    if (controller == 0) {
        return output;
    }

    bool previous_filter_on = controller->filter_on;
    bool previous_drain_open = controller->drain_open;
    controller_state_t previous_state = controller->state;

    /* Handle sensor timeout */
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT) {
        controller_set_safe_idle(controller);
        output.filter_on = false;
        output.drain_open = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = "STATE SAFE_IDLE";
        output.changed = true;
        return output;
    }

    /* Handle invalid input */
    if (input.kind == CONTROLLER_INPUT_INVALID_TURBIDITY ||
        input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        controller->has_valid_turbidity = false;
        controller->has_valid_level = false;
        controller->clear_streak_count = 0;
        controller->settling_started_ms = 0U;
        controller_set_safe_idle(controller);
        output.filter_on = false;
        output.drain_open = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = "STATE SAFE_IDLE";
        output.changed = true;
        return output;
    }

    /* Handle no input */
    if (input.kind == CONTROLLER_INPUT_NONE) {
        controller_set_safe_idle(controller);
        output.filter_on = false;
        output.drain_open = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = "STATE SAFE_IDLE";
        output.changed = true;
        return output;
    }

    /* Check for stale sensors */
    if (is_sensor_stale(controller->last_turbidity_ms, input.now_ms) ||
        is_sensor_stale(controller->last_level_ms, input.now_ms)) {
        controller_set_safe_idle(controller);
        output.filter_on = false;
        output.drain_open = false;
        output.state = CONTROLLER_STATE_SAFE_IDLE;
        output.state_name = "STATE SAFE_IDLE";
        output.changed = true;
        return output;
    }

    /* Update sensor state */
    if (input.kind == CONTROLLER_INPUT_TURBIDITY) {
        controller->has_valid_turbidity = true;
        controller->last_turbidity_ntu = input.turbidity_ntu;
        controller->last_turbidity_ms = input.now_ms;
    } else if (input.kind == CONTROLLER_INPUT_LEVEL) {
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
    }

    /* Check for complete state: level below minimum */
    if (controller->state != CONTROLLER_STATE_COMPLETE && controller->has_valid_level) {
        if (controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
            controller->state = CONTROLLER_STATE_COMPLETE;
            controller->filter_on = false;
            controller->drain_open = false;
            output.filter_on = false;
            output.drain_open = false;
            output.state = CONTROLLER_STATE_COMPLETE;
            output.state_name = "STATE COMPLETE";
            output.changed = true;
        }
    }

    /* Handle FILTERING state */
    if (controller->state == CONTROLLER_STATE_FILTERING) {
        /* If level is below threshold, go to complete */
        if (controller->has_valid_level && controller->last_level < CONTROLLER_COMPLETE_LEVEL) {
            controller->state = CONTROLLER_STATE_COMPLETE;
            controller->filter_on = false;
            controller->drain_open = false;
            output.filter_on = false;
            output.drain_open = false;
            output.state = CONTROLLER_STATE_COMPLETE;
            output.state_name = "STATE COMPLETE";
            output.changed = true;
        } else if (controller->has_valid_level && controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            /* Check turbidity and update clear streak */
            if (controller->has_valid_turbidity) {
                if (controller->last_turbidity_ntu > CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    /* Turbidity high, keep filtering */
                    output.filter_on = true;
                    output.drain_open = false;
                    output.state = CONTROLLER_STATE_FILTERING;
                    output.state_name = "STATE FILTERING";
                    output.changed = true;
                } else if (controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU) {
                    /* Turbidity clear, increment streak */
                    controller->clear_streak_count++;
                    if (controller->clear_streak_count >= CONTROLLER_CLEAR_STREAK_REQUIRED) {
                        /* Transition to settling */
                        controller->state = CONTROLLER_STATE_SETTLING;
                        controller->filter_on = false;
                        controller->drain_open = false;
                        controller->settling_started_ms = input.now_ms;
                        output.filter_on = false;
                        output.drain_open = false;
                        output.state = CONTROLLER_STATE_SETTLING;
                        output.state_name = "STATE SETTLING";
                        output.changed = true;
                    } else {
                        output.filter_on = true;
                        output.drain_open = false;
                        output.state = CONTROLLER_STATE_FILTERING;
                        output.state_name = "STATE FILTERING";
                        output.changed = true;
                    }
                }
            } else {
                /* No valid turbidity input, stay in filtering with filter on */
                output.filter_on = true;
                output.drain_open = false;
                output.state = CONTROLLER_STATE_FILTERING;
                output.state_name = "STATE FILTERING";
                output.changed = true;
            }
        } else {
            /* No valid level input, stay in filtering with filter on */
            output.filter_on = true;
            output.drain_open = false;
            output.state = CONTROLLER_STATE_FILTERING;
            output.state_name = "STATE FILTERING";
            output.changed = true;
        }
    }

    /* Handle SETTLING state */
    if (controller->state == CONTROLLER_STATE_SETTLING) {
        /* Check for disturbance - turbidity too high */
        if (controller->has_valid_turbidity && controller->last_turbidity_ntu > CONTROLLER_SETTLING_RESET_THRESHOLD_NTU) {
            /* Reset clear streak and return to filtering */
            controller->clear_streak_count = 0;
            controller->state = CONTROLLER_STATE_FILTERING;
            controller->filter_on = true;
            controller->drain_open = false;
            output.filter_on = true;
            output.drain_open = false;
            output.state = CONTROLLER_STATE_FILTERING;
            output.state_name = "STATE FILTERING";
            output.changed = true;
        } else {
            /* Check if settle time has elapsed and turbidity is clear */
            uint32_t settling_elapsed_ms = input.now_ms - controller->settling_started_ms;
            if (settling_elapsed_ms >= CONTROLLER_SETTLING_MS &&
                controller->has_valid_turbidity &&
                controller->last_turbidity_ntu <= CONTROLLER_CLEAR_THRESHOLD_NTU &&
                controller->has_valid_level &&
                controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
                /* Transition to draining */
                controller->state = CONTROLLER_STATE_DRAINING;
                controller->filter_on = false;
                controller->drain_open = true;
                output.filter_on = false;
                output.drain_open = true;
                output.state = CONTROLLER_STATE_DRAINING;
                output.state_name = "STATE DRAINING";
                output.changed = true;
            } else {
                /* Stay in settling */
                output.filter_on = false;
                output.drain_open = false;
                output.state = CONTROLLER_STATE_SETTLING;
                output.state_name = "STATE SETTLING";
                output.changed = false;
            }
        }
    }

    /* Handle DRAINING state */
    if (controller->state == CONTROLLER_STATE_DRAINING) {
        /* Check for disturbance - turbidity too high */
        if (controller->has_valid_turbidity && controller->last_turbidity_ntu > CONTROLLER_DRAINING_DISTURBANCE_THRESHOLD_NTU &&
            controller->has_valid_level && controller->last_level >= CONTROLLER_MIN_PROCESS_LEVEL) {
            /* Close drain, turn filter on, reset clear streak, return to filtering */
            controller->state = CONTROLLER_STATE_FILTERING;
            controller->filter_on = true;
            controller->drain_open = false;
            controller->clear_streak_count = 0;
            output.filter_on = true;
            output.drain_open = false;
            output.state = CONTROLLER_STATE_FILTERING;
            output.state_name = "STATE FILTERING";
            output.changed = true;
        } else {
            /* Stay in draining */
            output.filter_on = false;
            output.drain_open = true;
            output.state = CONTROLLER_STATE_DRAINING;
            output.state_name = "STATE DRAINING";
            output.changed = false;
        }
    }

    /* Update output based on current state */
    output.filter_on = controller->filter_on;
    output.drain_open = controller->drain_open;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed = (previous_filter_on != controller->filter_on) ||
                     (previous_drain_open != controller->drain_open) ||
                     (previous_state != controller->state);

    return output;
}

